// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Skip-scan (leapfrog step) coverage for {@link LmdbRecordIterator}: when a bound field beyond the index's range prefix
 * rejects a key, the iterator seeks past the whole non-matching run with MDB_SET_RANGE instead of stepping every key
 * with MDB_NEXT. Correctness is pinned differentially against a full-scan-and-filter reference; the skip effect itself
 * is observable through {@link RecordIterator#getSourceRowsScannedActual()}.
 */
public class LmdbRecordIteratorSkipScanTest {

	private TripleStore tripleStore;

	@BeforeEach
	public void before(@TempDir File dataDir) throws Exception {
		// spoc only: a subject+object probe leaves the object bound beyond the range prefix (KEY_FILTERED)
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc"), null);
	}

	@AfterEach
	public void after() throws Exception {
		if (tripleStore != null) {
			tripleStore.close();
		}
	}

	private List<long[]> drain(RecordIterator it) {
		List<long[]> result = new ArrayList<>();
		long[] quad;
		while ((quad = it.next()) != null) {
			result.add(quad.clone());
		}
		it.close();
		return result;
	}

	@Test
	public void boundObjectBeyondPrefixSkipsNonMatchingRuns() throws Exception {
		tripleStore.startTransaction();
		for (long p = 1; p <= 50; p++) {
			for (long o = 1; o <= 100; o++) {
				tripleStore.storeTriple(1, p, o, 1, true);
			}
		}
		// a second subject block: the skip seek must never escape the s=1 range
		for (long p = 1; p <= 10; p++) {
			for (long o = 1; o <= 100; o++) {
				tripleStore.storeTriple(2, p, o, 1, true);
			}
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordIterator it = tripleStore.getTriples(txn, 1, -1, 42, -1, true);
			List<long[]> result = drain(it);

			assertThat(result).hasSize(50);
			Set<Long> predicates = new HashSet<>();
			for (long[] quad : result) {
				assertThat(quad[TripleIndex.SUBJ_IDX]).isEqualTo(1L);
				assertThat(quad[TripleIndex.OBJ_IDX]).isEqualTo(42L);
				predicates.add(quad[TripleIndex.PRED_IDX]);
			}
			assertThat(predicates).hasSize(50);

			// 5_000 keys live under s=1; without skip-scan every one is stepped and scanned. With the
			// leapfrog step each (s,p) group costs a handful of keys, so the scan count collapses.
			assertThat(it.getSourceRowsScannedActual())
					.as("bound-object probe must leapfrog non-matching object runs instead of scanning all 5000 keys")
					.isLessThan(1_500L);
		}
	}

	@Test
	public void fillPathSkipsLikeNextPath() throws Exception {
		tripleStore.startTransaction();
		for (long p = 1; p <= 50; p++) {
			for (long o = 1; o <= 100; o++) {
				tripleStore.storeTriple(1, p, o, 1, true);
			}
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordIterator it = tripleStore.getTriples(txn, 1, -1, 42, -1, true);
			long[] buffer = new long[4 * 8];
			int total = 0;
			int rows;
			while ((rows = it.fill(buffer, 8)) > 0) {
				for (int i = 0; i < rows; i++) {
					assertThat(buffer[i * 4 + TripleIndex.OBJ_IDX]).isEqualTo(42L);
				}
				total += rows;
			}
			it.close();
			assertThat(total).isEqualTo(50);
			assertThat(it.getSourceRowsScannedActual())
					.as("fill() must leapfrog exactly like next()")
					.isLessThan(1_500L);
		}
	}

	@Test
	public void randomizedProbesMatchFullScanFilterReference() throws Exception {
		Random random = new Random(42);
		Set<Long> seen = new HashSet<>();
		List<long[]> data = new ArrayList<>();
		tripleStore.startTransaction();
		for (int i = 0; i < 2_000; i++) {
			long s = 1 + random.nextInt(8);
			long p = 1 + random.nextInt(6);
			long o = 1 + random.nextInt(40);
			long c = random.nextInt(3);
			long fingerprint = ((s * 31 + p) * 31 + o) * 31 + c;
			if (seen.add(fingerprint)) {
				data.add(new long[] { s, p, o, c });
				tripleStore.storeTriple(s, p, o, c, true);
			}
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			for (int round = 0; round < 200; round++) {
				long s = random.nextBoolean() ? 1 + random.nextInt(8) : -1;
				long p = random.nextBoolean() ? 1 + random.nextInt(6) : -1;
				long o = random.nextBoolean() ? 1 + random.nextInt(40) : -1;
				long c = random.nextBoolean() ? random.nextInt(3) : -1;

				List<long[]> expected = new ArrayList<>();
				for (long[] quad : data) {
					if ((s < 0 || quad[0] == s) && (p < 0 || quad[1] == p) && (o < 0 || quad[2] == o)
							&& (c < 0 || quad[3] == c)) {
						expected.add(quad);
					}
				}

				List<long[]> actual = drain(tripleStore.getTriples(txn, s, p, o, c, true));

				String probe = "probe s=" + s + " p=" + p + " o=" + o + " c=" + c;
				assertThat(actual).as(probe).hasSize(expected.size());
				Set<String> expectedKeys = new HashSet<>();
				for (long[] quad : expected) {
					expectedKeys.add(Arrays.toString(quad));
				}
				for (long[] quad : actual) {
					assertThat(expectedKeys).as(probe).contains(Arrays.toString(quad));
				}
			}
		}
	}
}
